import { Injectable } from '@angular/core';
import { HttpRequest, HttpHandler, HttpEvent, HttpInterceptor, HttpHandlerFn } from '@angular/common/http';
import { Observable } from 'rxjs';
import { inject } from '@angular/core';
import { environment } from '@environments/environment';
import { AccountService } from '@app/_services';

// Functional interceptor — used by app.config.ts with withInterceptors([...])
export function jwtInterceptor(request: HttpRequest<any>, next: HttpHandlerFn): Observable<HttpEvent<any>> {
  const accountService = inject(AccountService);
  const account = accountService.accountValue;
  const isLoggedIn = account?.jwtToken;
  const isApiUrl = request.url.startsWith(environment.apiUrl);
  if (isLoggedIn && isApiUrl) {
    request = request.clone({
      setHeaders: { Authorization: `Bearer ${account!.jwtToken}` }
    });
  }
  return next(request);
}

// Class-based interceptor — kept for legacy NgModule compatibility if needed
@Injectable()
export class JwtInterceptor implements HttpInterceptor {
  constructor(private accountService: AccountService) { }

  intercept(request: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    const account = this.accountService.accountValue;
    const isLoggedIn = account?.jwtToken;
    const isApiUrl = request.url.startsWith(environment.apiUrl);
    if (isLoggedIn && isApiUrl) {
      request = request.clone({
        setHeaders: { Authorization: `Bearer ${account!.jwtToken}` }
      });
    }
    return next.handle(request);
  }
}
